import json
import pathlib
import subprocess

import pytest

AC_UID = "ac08_fail_closed_v2"
AC_TYPE = "hook"

REPO_ROOT = pathlib.Path(__file__).resolve().parents[3]
HOOK_PATH = REPO_ROOT / "hooks" / "pretool-bash-safety.sh"
STABLE_STDERR_TOKEN = "bulk-commit-sentinel-write"

_FLAG = "/tmp/claude-bulk-allowed-testsid.flag"


def _run_hook_with_payload(hook_path, command):
    payload = {
        "tool_name": "Bash",
        "agent_id": "qa-test",
        "tool_input": {"command": command},
    }
    proc = subprocess.run(
        ["bash", str(hook_path)],
        input=json.dumps(payload),
        capture_output=True,
        text=True,
        timeout=10,
    )
    return proc.returncode, proc.stdout, proc.stderr


MATRIX = [
    ("a_unterminated_single_quote",
     f"cat {_FLAG} 'unterminated", 2),
    ("b_unterminated_double_quote",
     f'cat {_FLAG} "unterminated', 2),
]


@pytest.mark.parametrize(
    "case,command,expected_exit",
    MATRIX,
    ids=[row[0] for row in MATRIX],
)
def test_AC_08_fail_closed_on_tokenizer_error(case, command, expected_exit):
    """
    GIVEN: malformed command with unterminated quoting submitted to
           pretool-bash-safety.sh.
    WHEN:  Layer 1.F invokes the canonical tokenizer and exhausts list(lex).
    THEN:  list(lex) raises ValueError (typically 'No closing quotation');
           the try/except wrapper falls through to DENY (rc=2) — never
           silent allow.
    """
    assert HOOK_PATH.exists(), f"hook missing at {HOOK_PATH}"

    rc, _stdout, stderr = _run_hook_with_payload(HOOK_PATH, command)

    assert rc == expected_exit, (
        f"[{case}] expected exit {expected_exit}, got {rc}. "
        f"command={command!r}, stderr={stderr!r}"
    )
    assert STABLE_STDERR_TOKEN in stderr, (
        f"[{case}] expected stable stderr token "
        f"'{STABLE_STDERR_TOKEN}' in stderr (fail-closed), got stderr={stderr!r}"
    )
